const useAnimatedValue = (target: string, duration = 1200) => {
  const [display, setDisplay] = useState(target);
  const ref = useRef<HTMLDivElement>(null);
  const numericPart = parseInt(target.replace(/[^0-9]/g, ''));
  const suffix = target.replace(/[0-9]/g, '');

  useEffect(() => {
    if (isNaN(numericPart)) return;
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        const startTime = performance.now();
        const step = (now: number) => {
          const progress = Math.min((now - startTime) / duration, 1);
          const eased = 1 - Math.pow(1 - progress, 3);
          const current = Math.round(eased * numericPart);
          setDisplay(target.startsWith(String(numericPart)) ? `${current}${suffix}` : `${suffix}${current}`);
          if (progress < 1) requestAnimationFrame(step);
          else setDisplay(target);
        };
        requestAnimationFrame(step);
        observer.disconnect();
      }
    }, { threshold: 0.3 });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [target, duration]);
  return { display, ref };
};

